#include <bits/stdc++.h>
using namespace std;
const int N=16003,M=102;
struct Node{
    int l,p,s;
}a[M];
int n,m,f[M][N];
bool cmp(Node x,Node y){
    return x.s<y.s;
}
int calc(int i,int j){
    return f[i-1][j]-a[i].p*j;
}
int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&a[i].l,&a[i].p,&a[i].s);
    sort(a+1,a+m+1,cmp);
    for(int i=1;i<=m;i++){
        int q[N],l=1,r=0;
        for(int j=max(0,a[i].s-a[i].l);j<a[i].s;j++){
            while(l<=r && calc(i,q[r])<=calc(i,j))
                r--;
            q[++r]=j;
        }
        for(int j=1;j<=n;j++){
            f[i][j]=max(f[i-1][j],f[i][j-1]);
            if(j>=a[i].s){
                while(l<=r && q[l]<j-a[i].l)
                    l++;
                if(l<=r)
                    f[i][j]=max(f[i][j],calc(i,q[l])+a[i].p*j);
            }
        }
    }
    printf("%d",f[m][n]);
    return 0;
}
